grant insert on table "public"."schedule" to "authenticated";
grant references on table "public"."schedule" to "authenticated";
grant select on table "public"."schedule" to "authenticated";
grant trigger on table "public"."schedule" to "authenticated";
grant truncate on table "public"."schedule" to "authenticated";
grant update on table "public"."schedule" to "authenticated";
grant delete on table "public"."schedule" to "service_role";
grant insert on table "public"."schedule" to "service_role";
grant references on table "public"."schedule" to "service_role";
grant select on table "public"."schedule" to "service_role";
grant trigger on table "public"."schedule" to "service_role";
grant truncate on table "public"."schedule" to "service_role";
grant update on table "public"."schedule" to "service_role";

create policy "schedule_delete_manager_plus"
on "public"."schedule"
as permissive
for delete
to authenticated
using (public.has_org_role("organization_id", array['MANAGER'::public.organization_role, 'ADMIN'::public.organization_role]));

create policy "schedule_insert_agent_plus"
on "public"."schedule"
as permissive
for insert
to authenticated
with check (public.has_org_role("organization_id", array['AGENT'::public.organization_role, 'MANAGER'::public.organization_role, 'ADMIN'::public.organization_role]));

create policy "schedule_select_member"
on "public"."schedule"
as permissive
for select
to authenticated
using (public.is_org_member("organization_id"));

create policy "schedule_update_agent_plus"
on "public"."schedule"
as permissive
for update
to authenticated
using (public.has_org_role("organization_id", array['AGENT'::public.organization_role, 'MANAGER'::public.organization_role, 'ADMIN'::public.organization_role]))
with check (public.has_org_role("organization_id", array['AGENT'::public.organization_role, 'MANAGER'::public.organization_role, 'ADMIN'::public.organization_role]));
